/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
// React
import React from 'react';

// Styles
import styles from './style.module.css';

// Button
import Button from './components/button';

// Forms
// import Checkbox from './components/forms/checkbox';
// import Input from './components/forms/input';
// import TimePicker from './components/forms/timePicker';
// import Toggle from './components/forms/toggle';

// Typography
import H1 from './components/typography/h1';
import Text from './components/typography/text';



/* Design System Page
---------------------------------------------------------------------------------------------------- */
export default function DesignSystem() {
	/* Layout
	---------------------------------------------------------------------------------------------------- */
	return (
		<main className={styles.page_designSystem}>


			{/* Typography
			-------------------------------------------------- */}
			<H1 useTag='h2' className={styles.title}>Typography</H1>

			<div className={styles.divider}></div>
			<H1>Heading 1 - the quick brown<br />fox jumps over the lazy dog</H1>
			<div className={styles.divider}></div>

			<div className={styles.divider}></div>
			<Text size='l'>Text large - the quick brown<br />fox jumps over the lazy dog</Text>
			<div className={styles.divider}></div>

			<div className={styles.divider}></div>
			<Text size='m'>Text medium - the quick brown<br />fox jumps over the lazy dog</Text>
			<div className={styles.divider}></div>

			<div className={styles.divider}></div>
			<Text size='s'>Text small - the quick brown<br />fox jumps over the lazy dog</Text>
			<div className={styles.divider}></div>


			{/* Buttons
			-------------------------------------------------- */}
			<H1 useTag='h2' className={styles.title}>Buttons</H1>

			<Button href=''>Primary</Button>


			{/* Forms
			-------------------------------------------------- */}
			<H1 useTag='h2' className={styles.title}>Forms</H1>

			{/* <Input label='Field label' placeholder='Placeholder text' />
			<TimePicker label='Field label' placeholder='Placeholder text' />
			<Checkbox label='Field label' />
			<Toggle label='Field label' /> */}


		</main>
	);
}
