/*
	Name:
		Component Checkbox

	Description:
		Displays a checkbox form field.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		name
			Type: string
			Values: Any string
			Default: A random unique ID
			Description: Set the name attribute of this checkbox (e.g. <input name='XXX'>)

		state
			Type: string
			Values: 'normal', 'success', 'error'
			Default: ''
			Description: Set the visual state of this component.

		disabled
			Type: boolean
			Values: true, false
			Default: false
			Description: Disable the field.

		selected
			Type: boolean
			Values: true, false
			Default: false
			Description: Is this checkbox selected?

		label
			Type: string
			Values: Any string
			Default: ''
			Description: Display a field label.

		helperText
			Type: string
			Values: Any string
			Default: ''
			Description: Display helper text below this field.

		...rest
			All other props are passed to <input>.
*/



/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';
import Text from '../../typography/text';
import Icon from '../../icon';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	name?: string,
	state?: 'normal' | 'success' | 'error',
	disabled?: boolean,
	selected?: boolean,
	label?: string,
	helperText?: string
} & React.ComponentProps<'input'>;

function Checkbox({
	id = '',
	className = '',
	name = '',
	state = 'normal',
	disabled = false,
	selected = false,
	label = '',
	helperText = '',

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onChange = () => {},

	...rest
}: typedProps) {
	/* If there's no name prop generate a unique id
	-------------------------------------------------- */
	const uniqueId = React.useId();
	if (!name) {
		name = uniqueId;
	}


	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_checkbox, className];


	/* Label
	-------------------------------------------------- */
	let labelOutput: React.ReactNode;
	if (label) {
		labelOutput = (
			<label htmlFor={name}>
				<Text size='s' responsive={false} inheritWeight={true}>{label}</Text>
			</label>
		);
	}


	/* Helper text
	-------------------------------------------------- */
	let helperTextOutput: React.ReactNode;
	if (helperText) {
		helperTextOutput = (
			<div className={styles.helperText}>
				<Text size='xs'>{helperText}</Text>
			</div>
		);
	}


	/* Error text
	-------------------------------------------------- */
	const errorTextOutput = (
		<div className={styles.errorText}>
			<Text size='xs'>Error text</Text>
		</div>
	);


	/* Selected
	-------------------------------------------------- */
	// Create the selected state
	const [selectedState, setSelectedState] = React.useState(selected);

	// Handle field change
	function handleChange(event: React.ChangeEvent<HTMLInputElement>) {
		setSelectedState(event.currentTarget.checked);

		// Also call the event handler that could be passed in from the parent
		onChange(event);
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} data-state={state} data-disabled={disabled}>
			{/* Field */}
			<div className={styles.checkboxContainer} data-selected={selectedState}>
				<input
					type='checkbox'
					name={name}
					checked={selectedState}
					id={name}
					disabled={disabled}
					onChange={handleChange}
					{...rest}
				/>
				<Icon name='tick-02' size='xxs' style='stroke' type='sharp' strokeWidth={4} className={styles.icon} />
			</div>

			<div className={styles.textContainer}>
				{/* Label */}
				{labelOutput}

				{/* Helper text */}
				{helperTextOutput}

				{/* Error text */}
				{errorTextOutput}
			</div>
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Checkbox;

// Types
export type { typedProps as CheckboxTypes };
