/*
	Name:
		Component Input

	Description:
		Displays an input form field.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		name
			Type: string
			Values: Any string
			Default: A random unique ID
			Description: Set the name attribute of this input (e.g. <input name='XXX'>)

		fieldType
			Type: string
			Values: 'text', 'number', 'float', 'phone', 'email', 'url'
			Default: 'text'
			Description: Set the field type. Use this instead of passing "type" directly.

		state
			Type: string
			Values: 'normal', 'success', 'error'
			Default: ''
			Description: Set the visual state of this component.

		disabled
			Type: boolean
			Values: true, false
			Default: false
			Description: Disable the field.

		label
			Type: string
			Values: Any string
			Default: ''
			Description: Display a field label.

		helperText
			Type: string
			Values: Any string
			Default: ''
			Description: Display helper text below this field.

		prefix
			Type: string
			Values: Any string
			Default: ''
			Description: Display a prefix inside the field.

		suffix
			Type: string
			Values: Any string
			Default: ''
			Description: Display a suffix inside the field.

		icon
			Type: string
			Values: Any "Huge Icon" name
			Default: ''
			Description: Add an icon to the left of the field. Use any "Huge Icon" name (https://hugeicons.com/icons).

		...rest
			All other props are passed to <input>.
*/



/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import Text from '../../typography/text';
import Icon from '../../icon';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	name?: string,
	fieldType?: 'text' | 'number' | 'float' | 'phone' | 'email' | 'url',
	state?: 'normal' | 'success' | 'error',
	disabled?: boolean,
	label?: string,
	helperText?: string,
	prefix?: string,
	suffix?: string,
	icon?: string
} & React.ComponentProps<'input'>;

function Input({
	id = '',
	className = '',
	name = '',
	fieldType = 'text',
	state = 'normal',
	disabled = false,
	label = '',
	helperText = '',
	prefix = '',
	suffix = '',
	icon = '',

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onBlur = () => {},
	onFocus = () => {},
	onKeyDown = () => {},

	...rest
}: typedProps) {
	/* Functionality
	---------------------------------------------------------------------------------------------------- */
	/* Create state
	-------------------------------------------------- */
	// Focus state (true, false)
	const [focusState, setFocusState] = React.useState(false);

	// Initial field value (used to restore the value on escape keypress)
	const [initialValueState, setInitialValueState] = React.useState('');


	/* Create refs to target DOM elements
	-------------------------------------------------- */
	// HTML <input> field
	const fieldRef = React.useRef<HTMLInputElement>(null);


	/* If there's no name prop generate a unique id
	-------------------------------------------------- */
	const uniqueId = React.useId();
	if (!name) {
		name = uniqueId;
	}


	/* Focus the field (triggered on click of the suffix, prefix)
	-------------------------------------------------- */
	function focusField() {
		// Don't focus disabled fields
		if (disabled) {
			return;
		}

		// Focus the field
		fieldRef?.current?.focus();

		// Set the focus state
		setFocusState(true);
	}


	/* On blur of the <input> element
	-------------------------------------------------- */
	function handleBlur(event: React.FocusEvent<HTMLInputElement>) {
		setFocusState(false);

		// Also call the event handler that could be passed in from the parent
		onBlur(event);
	}


	/* On focus of the <input> element
	-------------------------------------------------- */
	function handleFocus(event: React.FocusEvent<HTMLInputElement>) {
		saveInitialValue();
		setFocusState(true);

		// Also call the event handler that could be passed in from the parent
		onFocus(event);
	}


	/* Support escape keypress to restore initial field value
	-------------------------------------------------- */
	// Save initial value (on focus)
	function saveInitialValue() {
		// Get the value of the field
		let value = fieldRef?.current?.value;

		// Make sure it's a string
		if (typeof value !== 'string') {
			value = '';
		}

		// Set the initial value state variable
		setInitialValueState(value);
	}

	// Check for the escape keypress (on key down)
	function handleKeyDown(event: React.KeyboardEvent<HTMLInputElement>) {
		// Target the field
		const field = fieldRef.current;

		// Make sure the field exists
		if (!field) {
			return;
		}

		// If escape was pressed
		if (event.key === "Escape") {
			// Restore the initial value
			field.value = initialValueState;

			// Blur the field
			field.blur();
		}

		// Also call the event handler that could be passed in from the parent
		onKeyDown(event);
	}



	/* Layout
	---------------------------------------------------------------------------------------------------- */
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_input, className];


	/* Setup the field type
	-------------------------------------------------- */
	/* Text (default)
	------------------------- */
	let inputType = 'text';
	let inputStep = '';

	// If a field type prop has been passed in
	if (fieldType) {
		/* Number
		------------------------- */
		if (fieldType === 'number') {
			inputType = 'number';

			// Allow whole numbers only
			inputStep = '1';
		}

		/* Float
		------------------------- */
		else if (fieldType === 'float') {
			inputType = 'number';

			// Allow any decimal places
			inputStep = 'any';
		}

		/* Phone
		------------------------- */
		else if (fieldType === 'phone') {
			inputType = 'tel';

			// Add an icon
			icon = 'call-02';
		}

		/* Email
		------------------------- */
		else if (fieldType === 'email') {
			inputType = 'email';

			// Add an icon
			icon = 'mail-01';
		}

		/* URL
		------------------------- */
		else if (fieldType === 'url') {
			inputType = 'url';
		}
	}


	/* Label
	-------------------------------------------------- */
	let labelOutput: React.ReactNode;
	if (label) {
		labelOutput = (
			<div className={styles.label}>
				<Text size='s' responsive={false} inheritWeight={true}>{label}</Text>
			</div>
		);
	}


	/* Helper text
	-------------------------------------------------- */
	let helperTextOutput: React.ReactNode;
	if (helperText) {
		helperTextOutput = (
			<div className={styles.helperText}>
				<Text size='xs'>{helperText}</Text>
			</div>
		);
	}


	/* Prefix
	-------------------------------------------------- */
	let prefixOutput: React.ReactNode;
	if (prefix) {
		prefixOutput = <div className={styles.prefix} onClick={focusField}>{prefix}</div>;
	}


	/* Suffix
	-------------------------------------------------- */
	let suffixOutput: React.ReactNode;
	if (suffix) {
		suffixOutput = <div className={styles.suffix} onClick={focusField}>{suffix}</div>;
	}


	/* Icon
	-------------------------------------------------- */
	let iconOutput: React.ReactNode;
	let iconClass = '';
	if (icon) {
		iconOutput = <div className={styles.icon}><Icon name={icon} size='xs' responsive={false} /></div>;
		iconClass = styles.hasIcon;
	}


	/* Error text
	-------------------------------------------------- */
	const errorTextOutput = (
		<div className={styles.errorText}>
			<Text size='xs'>Error text</Text>
		</div>
	);


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} data-state={state} data-disabled={disabled}>
			{/* Label */}
			{labelOutput}

			<div className={`${styles.fieldContainer} ${iconClass}`} data-focus={focusState} data-disabled={disabled}>
				{/* Icon */}
				{iconOutput}

				{/* Prefix */}
				{prefixOutput}

				{/* Field */}
				<input
					name={name}
					ref={fieldRef}
					disabled={disabled}
					type={inputType}
					step={inputStep}
					onBlur={handleBlur}
					onFocus={handleFocus}
					onKeyDown={handleKeyDown}
					{...rest}
				/>

				{/* Suffix */}
				{suffixOutput}
			</div>

			{/* Error text */}
			{errorTextOutput}

			{/* Helper text */}
			{helperTextOutput}
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Input;

// Types
export type { typedProps as InputTypes };
